-- AUTO-GENERATED local-dev seed for the Supabase CLI stack.
-- Runs automatically on `supabase start` / `supabase db reset` (see [db.seed] in config.toml).
--
-- 1) Grants: the local stack's default privileges do NOT give anon/authenticated
--    SELECT/INSERT/UPDATE/DELETE on public tables (they only get TRUNCATE/REFERENCES/TRIGGER),
--    which the app + RLS policies assume. Re-grant them here (RLS still enforces row access).
-- 2) Reference data: scholarships / universities / professors, converted from scripts/data/*.json,
--    so search features have data without needing the SSL-only npm seed scripts locally.

grant select, insert, update, delete on all tables in schema public to anon, authenticated, service_role;
grant usage, select on all sequences in schema public to anon, authenticated, service_role;

